import contextlib

class YazTransaction:
    """
    Context manager for managing database transactions with yaz (or any DBAPI 2.0 compatible library).
    """
    def __init__(self, connection):
        self.connection = connection
        self.cursor = None

    def __enter__(self):
        self.cursor = self.connection.cursor()
        return self.cursor

    def __exit__(self, exc_type, exc_val, exc_tb):
        if self.cursor:
            self.cursor.close()

        if exc_type is None:
            self.connection.commit()
        else:
            self.connection.rollback()
